var businessSetupGuard = (route, state2) => {
  const router = inject(Router);
  const token = typeof window !== "undefined" ? localStorage.getItem("authToken") : null;
  const profileCompleted = typeof window !== "undefined" && localStorage ? localStorage.getItem("profile") : null;
  if (!token) {
    router.navigate(["/"]);
    return false;
  }
  if (profileCompleted === "true") {
    router.navigate(["/home"]);
    return false;
  }
  return true;
};

